### 1. Full JSX for Dropdown Showcase Section (Lines 4460-4534)

```jsx
<ButtonShowcaseSection
  title="Dropdown"
  description="Pull-down selector with a dedicated arrow, used for option menus and popup lists."
>
  <div className="button-preview-row">
    <div className="button-preview-col">
      <div className="popup-trigger-anchor">
        <button
          type="button"
          className="popup-trigger-button"
          aria-haspopup="listbox"
          aria-expanded={popupOpen}
          onMouseEnter={() => setPopupHovered(true)}
          onMouseLeave={() => setPopupHovered(false)}
          onClick={() => setPopupOpen((prev: boolean) => !prev)}
        >
          <canvas
            ref={popupTriggerCanvasRef}
            className="popup-trigger-canvas"
          />
          <span className="popup-title-text">
            {popupSelection}
          </span>
          <img
            src={popupArrowUrl}
            alt=""
            className="popup-arrow-icon"
          />
        </button>
        {popupOpen && (
          <div className="popup-menu-demo" aria-label="Quality">
            <canvas
              ref={popupMenuCanvasRef}
              className="popup-menu-canvas"
            />
            {popupOptions.map((option) => (
              <div
                key={option}
                className={`popup-menu-option${popupSelection === option ? " selected" : ""}`}
                onClick={() => {
                  setPopupSelection(option);
                  setPopupOpen(false);
                }}
              >
                {option}
              </div>
            ))}
          </div>
        )}
      </div>
      <div className="button-state-label">Interactive</div>
    </div>
    <div className="button-preview-col">
      <button
        type="button"
        className="popup-trigger-button"
        disabled
      >
        <canvas
          ref={popupTriggerDisabledCanvasRef}
          className="popup-trigger-canvas"
        />
        <span className="popup-title-text popup-title-text-disabled">
          High
        </span>
        <img
          src={popupArrowUrl}
          alt=""
          className="popup-arrow-icon"
        />
      </button>
      <div className="button-state-label">Disabled</div>
    </div>
  </div>
</ButtonShowcaseSection>
```

### 2. Effect Blocks for Canvas Rendering

**Effect: Popup Trigger Canvas (Lines 2487-2527)**
```jsx
useEffect(() => {
  const canvas = popupTriggerCanvasRef.current;
  const bgUrlVal = popupOpen ? glueBgDownUrl : glueBgUrl;
  const borderUrlVal = popupOpen
    ? glueBorderedBorderDownUrl
    : glueBorderedBorderUrl;
  const hoverActive = popupHovered && !popupOpen;
  const hoverUrlVal = glueHoverUrl;
  if (!canvas || !bgUrlVal || !borderUrlVal) return;
  let cancelled = false;

  void Promise.all([
    loadDataUrlImage(bgUrlVal),
    loadDataUrlImage(borderUrlVal),
    hoverUrlVal ? loadDataUrlImage(hoverUrlVal) : Promise.resolve(null),
  ])
    .then(([bgImg, borderImg, hoverImg]) => {
      if (cancelled) return;
      drawGlueNineSliceToCanvas(
        canvas,
        bgImg,
        borderImg,
        hoverImg,
        hoverActive,
      );
    })
    .catch((err) => console.error(err));

  return () => {
    cancelled = true;
  };
}, [
  popupOpen,
  popupHovered,
  glueBgUrl,
  glueBgDownUrl,
  glueBorderedBorderUrl,
  glueBorderedBorderDownUrl,
  glueHoverUrl,
]);
```

**Effect: Popup Menu Canvas (Lines 2552-2573)**
```jsx
useEffect(() => {
  const canvas = popupMenuCanvasRef.current;
  const bgUrlVal = popupBgUrl || glueBgUrl;
  const borderUrlVal = glueBorderedBorderUrl;
  if (!popupOpen || !canvas || !bgUrlVal || !borderUrlVal) return;
  let cancelled = false;

  void Promise.all([
    loadDataUrlImage(bgUrlVal),
    loadDataUrlImage(borderUrlVal),
  ])
    .then(([bgImg, borderImg]) => {
      if (cancelled) return;
      drawGlueNineSliceToCanvas(canvas, bgImg, borderImg, null, false);
    })
    .catch((err) => console.error(err));

  return () => {
    cancelled = true;
  };
}, [popupOpen, popupBgUrl, glueBgUrl, glueBorderedBorderUrl]);
```

